import { z } from "zod";

import { implRunConfigSchema } from "./config-schema";

export const cliErrorSchema = z.object({
  code: z.string().min(1),
  message: z.string().min(1),
  detail: z.string().min(1).optional(),
});

export const cliArtifactRefSchema = z.object({
