  return {
    outcome: "ready-for-closeout",
    confirmedIssues: ["Epic verification ran before closeout."],
    disputedOrUnconfirmedIssues: [],
    readinessAssessment:
      "The epic is ready for the orchestrator-owned final gate.",
    recommendedNextStep:
