import { createClaudeCodeAdapter } from "./claude-code";
import { createCodexAdapter } from "./codex";
import { createCopilotAdapter } from "./copilot";
import type { ProviderAdapter, ProviderName } from "./shared";

interface ProviderAdapterOptions {
  env?: Record<string, string | undefined>;
}

export type {
  ProviderAdapter,
  ProviderExecutionRequest,
  ProviderExecutionResult,
  ProviderName,
} from "./shared";

export function createProviderAdapter(
  provider: ProviderName,
  options: ProviderAdapterOptions = {}
): ProviderAdapter {
  switch (provider) {
    case "claude-code":
      return createClaudeCodeAdapter(options);
    case "codex":
      return createCodexAdapter(options);
    case "copilot":
      return createCopilotAdapter(options);
  }
}

import {
  parseProviderPayload,
  runProviderCommand,
  type ProviderAdapter,
  type ProviderExecutionRequest,
} from "./shared";

interface CodexAdapterOptions {
  env?: Record<string, string | undefined>;
}

export function createCodexAdapter(
  options: CodexAdapterOptions = {}
): ProviderAdapter {
  return {
    provider: "codex",
    async execute<TResult>(
      request: ProviderExecutionRequest<TResult>
    ) {
      const args = request.resumeSessionId
        ? [
            "exec",
            "resume",
            "--json",
            request.resumeSessionId,
            request.prompt,
          ]
        : [
            "exec",
            "--json",
            "-m",
            request.model,
            "-c",
            `model_reasoning_effort=${request.reasoningEffort}`,
            request.prompt,
          ];
      const execution = await runProviderCommand({
        provider: "codex",
        executable: "codex",
        args,
        cwd: request.cwd,
        env: options.env,
        timeoutMs: request.timeoutMs,
      });

      if (execution.exitCode !== 0) {
        return execution;
      }

      const parsed = parseProviderPayload({
        stdout: execution.stdout,
        resultSchema: request.resultSchema,
      });

      return {
        ...execution,
        sessionId: parsed.sessionId ?? request.resumeSessionId,
        parsedResult: parsed.parsedResult,
        parseError: parsed.parseError,
      };
    },
  };
}

import {
  parseProviderPayload,
  runProviderCommand,
  type ProviderAdapter,
  type ProviderExecutionRequest,
} from "./shared";

interface ClaudeCodeAdapterOptions {
  env?: Record<string, string | undefined>;
}

export function createClaudeCodeAdapter(
  options: ClaudeCodeAdapterOptions = {}
): ProviderAdapter {
  return {
    provider: "claude-code",
    async execute<TResult>(
      request: ProviderExecutionRequest<TResult>
    ) {
      const args = request.resumeSessionId
        ? [
            "-p",
            request.prompt,
            "--resume",
            request.resumeSessionId,
            "--output-format",
            "json",
            "--model",
            request.model,
          ]
        : [
            "-p",
            request.prompt,
            "--output-format",
            "json",
            "--model",
            request.model,
            "--permission-mode",
            "acceptEdits",
          ];
      const execution = await runProviderCommand({
        provider: "claude-code",
        executable: "claude",
        args,
        cwd: request.cwd,
        env: options.env,
        timeoutMs: request.timeoutMs,
      });

      if (execution.exitCode !== 0) {
        return execution;
      }

      const parsed = parseProviderPayload({
        stdout: execution.stdout,
        resultSchema: request.resultSchema,
      });

      return {
        ...execution,
        sessionId: parsed.sessionId ?? request.resumeSessionId,
        parsedResult: parsed.parsedResult,
        parseError: parsed.parseError,
      };
    },
  };
}

import type { ProviderAdapter, ProviderExecutionRequest } from "./shared";

interface CopilotAdapterOptions {
  env?: Record<string, string | undefined>;
}

export function createCopilotAdapter(
  _options: CopilotAdapterOptions = {}
): ProviderAdapter {
  return {
    provider: "copilot",
    async execute<TResult>(
      request: ProviderExecutionRequest<TResult>
    ) {
      if (request.resumeSessionId) {
        return {
          provider: "copilot" as const,
          stdout: "",
          stderr: "Copilot continuation is not supported for retained implementor sessions in v1.",
          exitCode: 1,
          errorCode: "CONTINUATION_HANDLE_INVALID",
        };
      }

      return {
        provider: "copilot" as const,
        stdout: "",
        stderr: "Copilot execution is not implemented for retained implementor sessions in v1.",
        exitCode: 1,
      };
    },
  };
}

import { chmod, mkdir } from "node:fs/promises";
import { join } from "node:path";
import { describe, expect, test } from "bun:test";

import {
  ROOT,
  createSpecPack,
  createTempDir,
  readJsonLines,
  writeFakeProviderExecutable,
  writeTextFile,
} from "./test-helpers";

async function writeProviderBinary(params: {
  dir: string;
  name: string;
  version: string;
  authStatus?: "authenticated" | "missing";
  authBehavior?: "normal" | "timeout" | "unknown";
  captureCwdPath?: string;
  failureStderr?: string;
  authFailureStderr?: string;
}) {
  const authStatus = params.authStatus ?? "authenticated";
  const scriptPath = join(params.dir, params.name);
  const script = [
    "#!/bin/sh",
    params.captureCwdPath
      ? `printf '%s' \"$PWD\" > "${params.captureCwdPath}"`
      : "",
    'if [ "$1" = "--version" ]; then',
    params.failureStderr
      ? `  echo "${params.failureStderr}" >&2`
      : "",
    `  echo "${params.version}"`,
    "  exit 0",
    "fi",
    'if [ "$1" = "auth" ] && [ "$2" = "status" ]; then',
    params.authBehavior === "timeout"
      ? "  sleep 2"
      : params.authBehavior === "unknown"
        ? `  echo "${params.authFailureStderr ?? "transient provider failure"}" >&2`
        : authStatus === "authenticated"
          ? '  echo "authenticated"'
          : '  echo "missing" >&2',
    params.authBehavior === "timeout"
      ? "  exit 0"
      : params.authBehavior === "unknown"
        ? "  exit 70"
        : authStatus === "authenticated"
          ? "  exit 0"
          : "  exit 1",
    "fi",
    'echo "unexpected invocation" >&2',
    "exit 1",
    "",
  ].join("\n");
  await writeTextFile(scriptPath, script);
  await chmod(scriptPath, 0o755);
}

