435	export function cliResultEnvelopeSchema<T extends z.ZodTypeAny>(resultSchema: T) {
436	  return z
437	    .object({
438	      command: z.string().min(1),
439	      version: z.literal(1),
440	      status: cliStatusSchema,
441	      outcome: z.string().min(1),
442	      result: resultSchema.optional(),
443	      errors: z.array(cliErrorSchema),
444	      warnings: z.array(z.string()),
445	      artifacts: z.array(cliArtifactRefSchema),
446	      startedAt: z.string().min(1),
447	      finishedAt: z.string().min(1),
448	    })
449	    .superRefine((value, ctx) => {
450	      const expectedStatus = statusForOutcome(value.outcome);
451	      if (expectedStatus !== value.status) {
452	        ctx.addIssue({
453	          code: z.ZodIssueCode.custom,
454	          message: `Envelope status '${value.status}' does not match outcome '${value.outcome}'`,
455	          path: ["status"],
456	        });
457	      }
458	
459	      if (
460	        value.result &&
461	        typeof value.result === "object" &&
462	        "outcome" in value.result &&
463	        typeof value.result.outcome === "string" &&
464	        value.result.outcome !== value.outcome
465	      ) {
466	        ctx.addIssue({
467	          code: z.ZodIssueCode.custom,
468	          message: `Envelope outcome '${value.outcome}' does not match result outcome '${value.result.outcome}'`,
469	          path: ["outcome"],
470	        });
471	      }
472	    });
473	}
