475	export function createResultEnvelope<T>(input: {
476	  command: string;
477	  outcome: string;
478	  result?: T;
479	  errors?: CliError[];
480	  warnings?: string[];
481	  artifacts?: CliArtifactRef[];
482	  startedAt: string;
483	  finishedAt: string;
484	}) {
485	  return {
486	    command: input.command,
487	    version: 1 as const,
488	    status: statusForOutcome(input.outcome),
489	    outcome: input.outcome,
490	    result: input.result,
491	    errors: input.errors ?? [],
492	    warnings: input.warnings ?? [],
493	    artifacts: input.artifacts ?? [],
494	    startedAt: input.startedAt,
495	    finishedAt: input.finishedAt,
496	  };
497	}

