 50	function renderHumanSummary(envelope: OutputEnvelope) {
 51	  if (
 52	    typeof envelope.result !== "object" ||
 53	    envelope.result === null ||
 54	    !("confirmedIssues" in envelope.result)
 55	  ) {
 56	    return `epic-synthesize: ${envelope.outcome}`;
 57	  }
 58	
 59	  const result = envelope.result as {
 60	    confirmedIssues: string[];
 61	    disputedOrUnconfirmedIssues: string[];
 62	  };
 63	  return [
 64	    `epic-synthesize: ${envelope.outcome}`,
 65	    `confirmed: ${result.confirmedIssues.length}`,
 66	    `disputed: ${result.disputedOrUnconfirmedIssues.length}`,
 67	  ].join("\n");
 68	}
