 6	async function nextArtifactPathForGroup(
 7	  specPackRoot: string,
 8	  group: string,
 9	  fileName: string
10	): Promise<string> {
11	  const artifactDir = join(resolve(specPackRoot), "artifacts", group);
12	  await mkdir(artifactDir, { recursive: true });
13	
14	  const entries = await readdir(artifactDir, { withFileTypes: true });
15	  const existingCount = entries.filter(
16	    (entry) =>
17	      entry.isFile() && /^\d{3}-.+\.json$/.test(entry.name)
18	  ).length;
19	  const nextIndex = String(existingCount + 1).padStart(3, "0");
20	
21	  return join(artifactDir, `${nextIndex}-${fileName}.json`);
22	}
